# Set the default CTAS policy to block all inbound B2B collaboration
# and allow outbound (your users can visit other tenants)
$body = @{
    b2bCollaborationInbound = @{
        usersAndGroups = @{
            accessType = 'blocked'
            targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'blocked'
            targets    = @(@{ target = 'AllApplications'; targetType = 'application' })
        }
    }
    b2bCollaborationOutbound = @{
        usersAndGroups = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllApplications'; targetType = 'application' })
        }
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method PATCH \
    -Uri 'https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/default' \
    -Body $body -ContentType 'application/json'
Write-Host 'Default CTAS: inbound blocked, outbound allowed'

# Add a per-partner CTAS entry for fabrikam.com
$partnerTenantId = "aaaabbbb-0000-1111-2222-333344445555"

# Create the partner entry
Invoke-MgGraphRequest -Method POST \
    -Uri 'https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners' \
    -Body (@{ tenantId = $partnerTenantId } | ConvertTo-Json) \
    -ContentType 'application/json'

# Configure inbound: allow all users, all apps, trust partner MFA
$inbound = @{
    b2bCollaborationInbound = @{
        usersAndGroups = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllApplications'; targetType = 'application' })
        }
    }
    inboundTrust = @{
        isMfaAccepted                        = $true
        isCompliantDeviceAccepted            = $false
        isHybridAzureADJoinedDeviceAccepted  = $false
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$partnerTenantId" \
    -Body $inbound -ContentType 'application/json'
Write-Host "Partner $partnerTenantId: inbound allowed, MFA trusted"

# Restrict which of YOUR users can collaborate with external tenant fabrikam.com
# Only members of sg-approved-external-collaboration group may access fabrikam apps
$partnerTenantId = "aaaabbbb-0000-1111-2222-333344445555"
$groupId = "ccccdddd-5678-9012-bcde-f01234567890"   # sg-approved-external-collaboration

$outbound = @{
    b2bCollaborationOutbound = @{
        usersAndGroups = @{
            accessType = 'allowed'
            targets    = @(
                @{ target = $groupId; targetType = 'group' }
            )
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllApplications'; targetType = 'application' })
        }
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$partnerTenantId" \
    -Body $outbound -ContentType 'application/json'
Write-Host 'Outbound restricted to group members only'

# Enable B2B Direct Connect for Teams Shared Channels with a specific partner
# Both tenants MUST configure inbound AND outbound direct connect
$partnerTenantId = "aaaabbbb-0000-1111-2222-333344445555"

$dcBody = @{
    b2bDirectConnectInbound = @{
        usersAndGroups = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(
                # Microsoft Teams app ID for shared channels
                @{ target = 'Office365'; targetType = 'application' }
            )
        }
    }
    b2bDirectConnectOutbound = @{
        usersAndGroups = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'Office365'; targetType = 'application' })
        }
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$partnerTenantId" \
    -Body $dcBody -ContentType 'application/json'
Write-Host 'B2B Direct Connect enabled for Teams shared channels'

# Terraform: configure CTAS default policy and a per-partner entry
resource "azuread_cross_tenant_access_policy" "default" {}

resource "azuread_cross_tenant_access_policy_default" "config" {
  b2b_collaboration_inbound {
    applications {
      access_type = "blocked"
      targets {
        target      = "AllApplications"
        target_type = "application"
      }
    }
    users_and_groups {
      access_type = "blocked"
      targets {
        target      = "AllUsers"
        target_type = "user"
      }
    }
  }
}

resource "azuread_cross_tenant_access_policy_partner" "fabrikam" {
  tenant_id = "aaaabbbb-0000-1111-2222-333344445555"

  b2b_collaboration_inbound {
    applications {
      access_type = "allowed"
      targets {
        target      = "AllApplications"
        target_type = "application"
      }
    }
    users_and_groups {
      access_type = "allowed"
      targets {
        target      = "AllUsers"
        target_type = "user"
      }
    }
  }

  inbound_trust {
    is_mfa_accepted                           = true
    is_compliant_device_accepted              = false
    is_hybrid_azure_ad_joined_device_accepted = false
  }
}

# Bulk-configure CTAS for multiple partners from a CSV
# partners.csv: tenantId,allowInbound,trustMFA
# aaaabbbb-...,true,true
# ccccdddd-...,true,false

$partners = Import-Csv -Path ./partners.csv
foreach ($p in $partners) {
    # Create entry if it doesn't exist
    $existing = $null
    try {
        $existing = Invoke-MgGraphRequest -Method GET \
            -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$($p.tenantId)"
    } catch {}

    if (-not $existing) {
        Invoke-MgGraphRequest -Method POST \
            -Uri 'https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners' \
            -Body (@{ tenantId = $p.tenantId } | ConvertTo-Json) \
            -ContentType 'application/json'
    }

    $access = if ($p.allowInbound -eq 'true') { 'allowed' } else { 'blocked' }
    $body = @{
        b2bCollaborationInbound = @{
            usersAndGroups = @{ accessType = $access; targets = @(@{ target = 'AllUsers'; targetType = 'user' }) }
            applications   = @{ accessType = $access; targets = @(@{ target = 'AllApplications'; targetType = 'application' }) }
        }
        inboundTrust = @{ isMfaAccepted = [bool]::Parse($p.trustMFA) }
    } | ConvertTo-Json -Depth 8

    Invoke-MgGraphRequest -Method PATCH \
        -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$($p.tenantId)" \
        -Body $body -ContentType 'application/json'
    Write-Host "Configured partner: $($p.tenantId) | inbound=$access | trustMFA=$($p.trustMFA)"
}

# Tenant Restrictions v2 (TRv2): prevent your managed devices from accessing
# any external tenant not in your allowlist — enforced at the network/OS layer

# Step 1: Enable TRv2 in CTAS default policy
$trv2 = @{
    tenantRestrictions = @{
        usersAndGroups = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(
                @{ target = 'AllApplications'; targetType = 'application' }
            )
        }
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method PATCH \
    -Uri 'https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/default' \
    -Body $trv2 -ContentType 'application/json'

# Step 2: On Windows managed devices, set the registry key (deployed via Intune)
# HKEY_LOCAL_MACHINE\SOFTWARE\Policies\Microsoft\Windows\NetworkIsolation
# EnterpriseProxyServers: your proxy address that injects the Restrict-Access-To-Tenants header
# This forces all AAD token requests through the proxy, which enforces the TRv2 policy

# Step 3: On the proxy, inject these headers on all login.microsoftonline.com requests:
# Restrict-Access-To-Tenants: contoso.onmicrosoft.com,fabrikam.com
# Restrict-Access-Context: <your tenant ID>
# sec-Restrict-Tenant-Access-Policy: restrict-msa
